let spikeStart = startofday(datetime({SpikeRange:startISO}));
let spikeEnd = startofday(datetime({SpikeRange:endISO}));
let baseStart = startofday(datetime({BaselineRange:startISO}));
let baseEnd = startofday(datetime({BaselineRange:endISO}));
let spikeDays = toreal(toint((spikeEnd - spikeStart) / 1d));
let baseDays = toreal(toint((baseEnd - baseStart) / 1d));
let spike = {Table} | where Timestamp >= spikeStart and Timestamp < spikeEnd | summarize Total = toreal(count()) | extend Period = strcat("Spike (last ", toint(spikeDays), " d, avg/day)"), PerDay = Total / spikeDays;
let base = {Table} | where Timestamp >= baseStart and Timestamp < baseEnd | summarize Total = toreal(count()) | extend Period = strcat("Baseline (", toint(baseDays), " d, avg/day)"), PerDay = Total / baseDays;
union base, spike
| project Period, EventsPerDay = round(PerDay, 0)
| order by Period asc

let spikeStart = startofday(datetime({SpikeRange:startISO}));
let spikeEnd = startofday(datetime({SpikeRange:endISO}));
let baseStart = startofday(datetime({BaselineRange:startISO}));
let baseEnd = startofday(datetime({BaselineRange:endISO}));
let windowStart = min_of(baseStart, spikeStart);
let windowEnd = max_of(baseEnd, spikeEnd);
{Table}
| where Timestamp >= windowStart and Timestamp < windowEnd
| summarize Count = toreal(count()) by Day = bin(Timestamp, 1d)
| order by Day asc

let spikeStart = datetime({SpikeRange:startISO});
let spikeEnd = datetime({SpikeRange:endISO});
let agg = materialize(
    {Table}
    | where Timestamp between (spikeStart .. spikeEnd)
    | extend Vendor = column_ifexists('InitiatingProcessVersionInfoCompanyName', '')
    | extend Product = column_ifexists('InitiatingProcessVersionInfoProductName', '')
    | summarize hint.strategy=shuffle hint.shufflekey=ActionType
        Rows = count(),
        DistinctDevices = dcount(DeviceName),
        TopVendors = make_set(Vendor, 5),
        TopProducts = make_set(Product, 5),
        TopParents = make_set(InitiatingProcessFileName, 5)
        by ActionType
);
let total = toscalar(agg | summarize sum(Rows));
agg
| extend PctOfSpike = round(100.0 * Rows / todouble(total), 2)
| top 20 by Rows desc
| project ActionType, Rows, PctOfSpike, DistinctDevices, TopVendors, TopProducts, TopParents

let spikeStart = datetime({SpikeRange:startISO});
let spikeEnd = datetime({SpikeRange:endISO});
let baseDuration = datetime({BaselineRange:endISO}) - datetime({BaselineRange:startISO});
let baseStart = spikeStart - baseDuration;
let baseEnd = spikeStart;
let spikeDays = toscalar(print d = (spikeEnd - spikeStart) / 1d);
let baseDays = toscalar(print d = baseDuration / 1d);
let spike =
    {Table}
    | where Timestamp >= spikeStart and Timestamp <= spikeEnd
    | summarize SpikePerDay = todouble(count()) / spikeDays by ActionType;
let base =
    {Table}
    | where Timestamp >= baseStart and Timestamp < baseEnd
    | summarize BasePerDay = todouble(count()) / baseDays by ActionType;
spike
| join kind=fullouter base on ActionType
| extend ActionType = coalesce(ActionType, ActionType1), SpikePerDay = coalesce(SpikePerDay, real(0)), BasePerDay = coalesce(BasePerDay, real(0))
| extend Delta = SpikePerDay - BasePerDay
| extend Ratio = iff(BasePerDay > 0, round(SpikePerDay / BasePerDay, 3), real(null))
| project ActionType, BasePerDay = round(BasePerDay, 3), SpikePerDay = round(SpikePerDay, 3), Delta = round(Delta, 3), Ratio
| order by Delta desc

let spikeStart = datetime({SpikeRange:startISO});
let spikeEnd = datetime({SpikeRange:endISO});
let baseStart = datetime({BaselineRange:startISO});
let baseEnd = datetime({BaselineRange:endISO});
let spikeDays = toscalar(print d = (spikeEnd - spikeStart) / 1d);
let baseDays = toscalar(print d = (baseEnd - baseStart) / 1d);
let spike = materialize(
    {Table}
    | where Timestamp between (spikeStart .. spikeEnd)
    | summarize hint.strategy=shuffle hint.shufflekey=ActionType
        SpikePerDay = todouble(count()) / spikeDays
        by ActionType
);
let base = materialize(
    {Table}
    | where Timestamp between (baseStart .. baseEnd)
    | summarize hint.strategy=shuffle hint.shufflekey=ActionType
        BasePerDay = todouble(count()) / baseDays
        by ActionType
);
spike
| join kind=fullouter base on ActionType
| extend ActionType = coalesce(ActionType, ActionType1)
| extend SpikePerDay = coalesce(SpikePerDay, real(0)), BasePerDay = coalesce(BasePerDay, real(0))
| extend Delta = SpikePerDay - BasePerDay
| order by Delta desc
| take 15
| project ActionType, BasePerDay = round(BasePerDay, 0), SpikePerDay = round(SpikePerDay, 0), Delta = round(Delta, 0)

let spikeStart = datetime({SpikeRange:startISO});
let spikeEnd = datetime({SpikeRange:endISO});
let baseRangeStart = datetime({BaselineRange:startISO});
let baseRangeEnd = datetime({BaselineRange:endISO});
let baseDuration = baseRangeEnd - baseRangeStart;
let baseStart = spikeStart - baseDuration;
let baseEnd = spikeStart;
let spikeDays = toscalar(print d = (spikeEnd - spikeStart) / 1d);
let baseDays = toscalar(print d = (baseEnd - baseStart) / 1d);
let threshold = toreal('{Threshold}');
let topParents = toscalar(
    {Table}
    | where Timestamp between (spikeStart .. spikeEnd)
    | summarize hint.strategy=shuffle hint.shufflekey=InitiatingProcessFileName SpikeCount = count() by InitiatingProcessFileName
    | top 50 by SpikeCount desc
    | summarize make_set(InitiatingProcessFileName)
);
let spike = {Table}
    | where Timestamp between (spikeStart .. spikeEnd)
    | where InitiatingProcessFileName in (topParents)
    | extend ChildName = column_ifexists('FileName', '')
    | summarize Spike = todouble(count()) / spikeDays, DistinctDevices = dcount(DeviceName)
        by InitiatingProcessFileName, ChildName;
let base = {Table}
    | where Timestamp between (baseStart .. baseEnd)
    | where InitiatingProcessFileName in (topParents)
    | extend ChildName = column_ifexists('FileName', '')
    | summarize Baseline = todouble(count()) / baseDays
        by InitiatingProcessFileName, ChildName;
let attribution = {Table}
    | where Timestamp between (spikeStart .. spikeEnd)
    | where InitiatingProcessFileName in (topParents)
    | extend Vendor = column_ifexists('InitiatingProcessVersionInfoCompanyName', '')
    | extend Product = column_ifexists('InitiatingProcessVersionInfoProductName', '')
    | extend ParentPath = column_ifexists('InitiatingProcessFolderPath', '')
    | summarize
        Vendors = make_set_if(Vendor, isnotempty(Vendor), 3),
        Products = make_set_if(Product, isnotempty(Product), 3),
        ParentPaths = make_set_if(ParentPath, isnotempty(ParentPath), 3)
        by InitiatingProcessFileName;
spike
| join kind=leftouter base on InitiatingProcessFileName, ChildName
| extend Baseline = coalesce(Baseline, real(0))
| extend Delta = Spike - Baseline
| join kind=leftouter attribution on InitiatingProcessFileName
| extend AboveThreshold = iff(Delta > threshold, 'true', 'false')
| extend Vendors = iff(array_length(Vendors) == 0, dynamic(['(unknown)']), Vendors)
| extend Products = iff(array_length(Products) == 0, dynamic(['(unknown)']), Products)
| project
    AboveThreshold,
    Vendors,
    Products,
    ParentFileName = InitiatingProcessFileName,
    ParentPaths,
    ChildName,
    DistinctDevices,
    Baseline = round(Baseline, 3),
    Spike = round(Spike, 3),
    Delta = round(Delta, 3)
| top 50 by Delta desc
